parameters.jsCode:
try {
  const raw = $input.first().json.content?.[0]?.text || '';
  let c = {};
  try { c = JSON.parse(raw); }
  catch(e) { const m = raw.match(/\{[\s\S]*\}/); if(m) try { c = JSON.parse(m[0]); } catch(e2) {} }
  const biz = $('Get Business').first().json;
  return [{ json: { ...c, business_id: biz.id, business_name: biz.business_name, email: biz.email, first_name: biz.first_name } }];
} catch(e) {
  return [{ json: { error: e.message } }];
}
